package com.schwab.urlShortener.service;

import com.google.zxing.BarcodeFormat;
import com.google.zxing.WriterException;
import com.google.zxing.client.j2se.MatrixToImageWriter;
import com.google.zxing.common.BitMatrix;
import com.google.zxing.qrcode.QRCodeWriter;
import org.springframework.stereotype.Service;

import java.io.ByteArrayOutputStream;
import java.io.IOException;

@Service
public class QrCodeService {

    public byte[] generateQrCodePng(String data, int width, int height) {
        try {
            QRCodeWriter qrCodeWriter = new QRCodeWriter();
            BitMatrix bitMatrix = qrCodeWriter.encode(data, BarcodeFormat.QR_CODE, width, height);

            ByteArrayOutputStream outputStream = new ByteArrayOutputStream();
            MatrixToImageWriter.writeToStream(bitMatrix, "PNG", outputStream);
            return outputStream.toByteArray();
        } catch (WriterException | IOException e) {
            throw new QrCodeGenerationException("Failed to generate QR code", e);
        }
    }
}

package com.schwab.urlShortener.service;

public class QrCodeGenerationException extends RuntimeException {

    public QrCodeGenerationException(String message, Throwable cause) {
        super(message, cause);
    }
}

package com.schwab.urlShortener.api;

import com.schwab.urlShortener.domain.LinkStats;
import com.schwab.urlShortener.domain.ShortLink;
import com.schwab.urlShortener.service.QrCodeService;
import com.schwab.urlShortener.service.ShortLinkService;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpStatus;
import org.springframework.http.MediaType;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.Map;

@RestController
@RequestMapping("/api/v1/links")
public class ShortLinkController {

    private final ShortLinkService service;
    private final QrCodeService qrCodeService;
    private final String baseUrl;
    private final String redirectPath;

    public ShortLinkController(
            ShortLinkService service,
            QrCodeService qrCodeService,
            @Value("${app.base-url}") String baseUrl,
            @Value("${app.redirect-path}") String redirectPath) {
        this.service = service;
        this.qrCodeService = qrCodeService;
        this.baseUrl = baseUrl;
        this.redirectPath = redirectPath;
    }

    @PostMapping
    public ResponseEntity<Map<String, String>> createShortLink(@RequestBody Map<String, String> request) {
        String longUrl = request.get("url");
        ShortLink shortLink = service.create(longUrl);

        String shortUrl = baseUrl + redirectPath + shortLink.getShortCode();

        return ResponseEntity
                .status(HttpStatus.CREATED)
                .body(Map.of(
                        "shortCode", shortLink.getShortCode(),
                        "shortUrl", shortUrl,
                        "longUrl", shortLink.getLongUrl()
                ));
    }

    @GetMapping("/{shortCode}")
    public ResponseEntity<Map<String, Object>> getShortLink(@PathVariable String shortCode) {
        ShortLink shortLink = service.resolve(shortCode);

        String shortUrl = baseUrl + redirectPath + shortLink.getShortCode();

        return ResponseEntity.ok(Map.of(
                "shortCode", shortLink.getShortCode(),
                "shortUrl", shortUrl,
                "longUrl", shortLink.getLongUrl(),
                "createdAt", shortLink.getCreatedAt()
        ));
    }

    @GetMapping("/{shortCode}/stats")
    public ResponseEntity<LinkStats> getStats(@PathVariable String shortCode) {
        LinkStats stats = service.getStats(shortCode);
        return ResponseEntity.ok(stats);
    }

    @GetMapping("/{shortCode}/qr")
    public ResponseEntity<byte[]> getQrCode(@PathVariable String shortCode) {
        ShortLink shortLink = service.resolve(shortCode);

        String shortUrl = baseUrl + redirectPath + shortLink.getShortCode();

        byte[] qrCodeImage = qrCodeService.generateQrCodePng(shortUrl, 250, 250);

        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.IMAGE_PNG);

        return ResponseEntity.ok()
                .headers(headers)
                .body(qrCodeImage);
    }
}

package com.schwab.urlShortener.service;

import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.*;

class QrCodeServiceTest {

    private final QrCodeService qrCodeService = new QrCodeService();

    @Test
    void generateQrCodePng_shouldReturnValidPngByteArray() {
        String testData = "https://example.com/abc123";

        byte[] result = qrCodeService.generateQrCodePng(testData, 250, 250);

        assertNotNull(result);
        assertTrue(result.length > 0);
        assertTrue(result[0] == (byte) 0x89 && result[1] == 0x50 && result[2] == 0x4E && result[3] == 0x47);
    }

    @Test
    void generateQrCodePng_shouldHandleDifferentDimensions() {
        String testData = "https://example.com/test";

        byte[] result = qrCodeService.generateQrCodePng(testData, 100, 100);

        assertNotNull(result);
        assertTrue(result.length > 0);
    }

    @Test
    void generateQrCodePng_shouldHandleEmptyString() {
        byte[] result = qrCodeService.generateQrCodePng("", 250, 250);

        assertNotNull(result);
        assertTrue(result.length > 0);
    }

    @Test
    void generateQrCodePng_shouldHandleLongUrls() {
        String longUrl = "https://example.com/" + "a".repeat(1000);

        byte[] result = qrCodeService.generateQrCodePng(longUrl, 250, 250);

        assertNotNull(result);
        assertTrue(result.length > 0);
    }
}

package com.schwab.urlShortener.api;

import com.schwab.urlShortener.domain.LinkStats;
import com.schwab.urlShortener.domain.ShortLink;
import com.schwab.urlShortener.service.QrCodeService;
import com.schwab.urlShortener.service.ShortLinkNotFoundException;
import com.schwab.urlShortener.service.ShortLinkService;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.WebMvcTest;
import org.springframework.boot.test.mock.mockito.MockBean;
import org.springframework.http.MediaType;
import org.springframework.test.web.servlet.MockMvc;

import java.time.Instant;

import static org.mockito.ArgumentMatchers.*;
import static org.mockito.Mockito.when;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;

@WebMvcTest(ShortLinkController.class)
class ShortLinkControllerTest {

    @Autowired
    private MockMvc mockMvc;

    @MockBean
    private ShortLinkService service;

    @MockBean
    private QrCodeService qrCodeService;

    @Test
    void createShortLink_shouldReturnCreatedLink() throws Exception {
        ShortLink shortLink = new ShortLink("abc123", "https://example.com", Instant.now());
        when(service.create(anyString())).thenReturn(shortLink);

        mockMvc.perform(post("/api/v1/links")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content("{\"url\":\"https://example.com\"}"))
                .andExpect(status().isCreated())
                .andExpect(jsonPath("$.shortCode").value("abc123"))
                .andExpect(jsonPath("$.longUrl").value("https://example.com"))
                .andExpect(jsonPath("$.shortUrl").exists());
    }

    @Test
    void getShortLink_shouldReturnLinkDetails() throws Exception {
        ShortLink shortLink = new ShortLink("abc123", "https://example.com", Instant.now());
        when(service.resolve("abc123")).thenReturn(shortLink);

        mockMvc.perform(get("/api/v1/links/abc123"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.shortCode").value("abc123"))
                .andExpect(jsonPath("$.longUrl").value("https://example.com"))
                .andExpect(jsonPath("$.shortUrl").exists())
                .andExpect(jsonPath("$.createdAt").exists());
    }

    @Test
    void getShortLink_shouldReturn404ForUnknownCode() throws Exception {
        when(service.resolve("unknown")).thenThrow(new ShortLinkNotFoundException("unknown"));

        mockMvc.perform(get("/api/v1/links/unknown"))
                .andExpect(status().isNotFound());
    }

    @Test
    void getStats_shouldReturnLinkStatistics() throws Exception {
        LinkStats stats = new LinkStats("abc123", "https://example.com", 42, Instant.now(), Instant.now());
        when(service.getStats("abc123")).thenReturn(stats);

        mockMvc.perform(get("/api/v1/links/abc123/stats"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.shortCode").value("abc123"))
                .andExpect(jsonPath("$.accessCount").value(42));
    }

    @Test
    void getQrCode_shouldReturnPngImageFor ValidShortCode() throws Exception {
        ShortLink shortLink = new ShortLink("abc123", "https://example.com", Instant.now());
        when(service.resolve("abc123")).thenReturn(shortLink);

        byte[] mockQrCode = new byte[]{(byte) 0x89, 0x50, 0x4E, 0x47, 0x0D, 0x0A, 0x1A, 0x0A};
        when(qrCodeService.generateQrCodePng(anyString(), eq(250), eq(250))).thenReturn(mockQrCode);

        mockMvc.perform(get("/api/v1/links/abc123/qr"))
                .andExpect(status().isOk())
                .andExpect(content().contentType(MediaType.IMAGE_PNG))
                .andExpect(content().bytes(mockQrCode));
    }

    @Test
    void getQrCode_shouldReturn404ForUnknownShortCode() throws Exception {
        when(service.resolve("unknown")).thenThrow(new ShortLinkNotFoundException("unknown"));

        mockMvc.perform(get("/api/v1/links/unknown/qr"))
                .andExpect(status().isNotFound());
    }
}

package com.schwab.urlShortener.api;

import com.schwab.urlShortener.service.InvalidUrlException;
import com.schwab.urlShortener.service.QrCodeGenerationException;
import com.schwab.urlShortener.service.ShortCodeGenerationException;
import com.schwab.urlShortener.service.ShortLinkNotFoundException;
import org.springframework.http.HttpStatus;
import org.springframework.http.ProblemDetail;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.RestControllerAdvice;

import java.net.URI;

@RestControllerAdvice
public class GlobalExceptionHandler {

    @ExceptionHandler(InvalidUrlException.class)
    public ProblemDetail handleInvalidUrl(InvalidUrlException ex) {
        ProblemDetail problem = ProblemDetail.forStatusAndDetail(
                HttpStatus.BAD_REQUEST,
                ex.getMessage()
        );
        problem.setType(URI.create("https://api.schwab.com/problems/invalid-url"));
        problem.setTitle("Invalid URL");
        return problem;
    }

    @ExceptionHandler(ShortLinkNotFoundException.class)
    public ProblemDetail handleShortLinkNotFound(ShortLinkNotFoundException ex) {
        ProblemDetail problem = ProblemDetail.forStatusAndDetail(
                HttpStatus.NOT_FOUND,
                ex.getMessage()
        );
        problem.setType(URI.create("https://api.schwab.com/problems/short-link-not-found"));
        problem.setTitle("Short Link Not Found");
        return problem;
    }

    @ExceptionHandler(ShortCodeGenerationException.class)
    public ProblemDetail handleShortCodeGeneration(ShortCodeGenerationException ex) {
        ProblemDetail problem = ProblemDetail.forStatusAndDetail(
                HttpStatus.INTERNAL_SERVER_ERROR,
                ex.getMessage()
        );
        problem.setType(URI.create("https://api.schwab.com/problems/short-code-generation"));
        problem.setTitle("Short Code Generation Failed");
        return problem;
    }

    @ExceptionHandler(QrCodeGenerationException.class)
    public ProblemDetail handleQrCodeGeneration(QrCodeGenerationException ex) {
        ProblemDetail problem = ProblemDetail.forStatusAndDetail(
                HttpStatus.INTERNAL_SERVER_ERROR,
                ex.getMessage()
        );
        problem.setType(URI.create("https://api.schwab.com/problems/qr-code-generation"));
        problem.setTitle("QR Code Generation Failed");
        return problem;
    }
}

package com.schwab.urlShortener.service;

import org.junit.jupiter.api.Test;

import static org.assertj.core.api.Assertions.*;

class QrCodeServiceTest {

    private final QrCodeService qrCodeService = new QrCodeService();

    @Test
    void generateQrCodePng_producesValidPngWithExpectedHeader() {
        String testData = "https://example.com/abc123";

        byte[] result = qrCodeService.generateQrCodePng(testData, 250, 250);

        assertThat(result).isNotEmpty();
        assertThat(result).hasSizeGreaterThan(8);
        // PNG file signature: 0x89 0x50 0x4E 0x47 0x0D 0x0A 0x1A 0x0A
        assertThat(result[0]).isEqualTo((byte) 0x89);
        assertThat(result[1]).isEqualTo((byte) 0x50);
        assertThat(result[2]).isEqualTo((byte) 0x4E);
        assertThat(result[3]).isEqualTo((byte) 0x47);
    }

    @Test
    void generateQrCodePng_withSmallDimensions_producesValidOutput() {
        String testData = "https://example.com/test";

        byte[] result = qrCodeService.generateQrCodePng(testData, 50, 50);

        assertThat(result).isNotEmpty();
        assertThat(result[0]).isEqualTo((byte) 0x89);
    }

    @Test
    void generateQrCodePng_withLargeDimensions_producesLargerOutput() {
        String testData = "https://example.com/test";

        byte[] smallResult = qrCodeService.generateQrCodePng(testData, 100, 100);
        byte[] largeResult = qrCodeService.generateQrCodePng(testData, 500, 500);

        assertThat(largeResult.length).isGreaterThan(smallResult.length);
    }

    @Test
    void generateQrCodePng_withEmptyString_producesValidQrCode() {
        byte[] result = qrCodeService.generateQrCodePng("", 250, 250);

        assertThat(result).isNotEmpty();
        assertThat(result[0]).isEqualTo((byte) 0x89);
    }

    @Test
    void generateQrCodePng_withLongUrl_producesValidQrCode() {
        String longUrl = "https://example.com/" + "a".repeat(1000);

        byte[] result = qrCodeService.generateQrCodePng(longUrl, 250, 250);

        assertThat(result).isNotEmpty();
        assertThat(result[0]).isEqualTo((byte) 0x89);
    }

    @Test
    void generateQrCodePng_withSpecialCharacters_producesValidQrCode() {
        String urlWithSpecialChars = "https://example.com/?param=value&foo=bar#section";

        byte[] result = qrCodeService.generateQrCodePng(urlWithSpecialChars, 250, 250);

        assertThat(result).isNotEmpty();
        assertThat(result[0]).isEqualTo((byte) 0x89);
    }

    @Test
    void generateQrCodePng_withNegativeDimensions_throwsQrCodeGenerationException() {
        assertThatThrownBy(() -> qrCodeService.generateQrCodePng("https://example.com", -100, 250))
                .isInstanceOf(QrCodeGenerationException.class)
                .hasMessageContaining("Failed to generate QR code")
                .hasCauseInstanceOf(IllegalArgumentException.class);
    }

    @Test
    void generateQrCodePng_withZeroDimensions_throwsQrCodeGenerationException() {
        assertThatThrownBy(() -> qrCodeService.generateQrCodePng("https://example.com", 0, 0))
                .isInstanceOf(QrCodeGenerationException.class)
                .hasMessageContaining("Failed to generate QR code");
    }

    @Test
    void generateQrCodePng_withNullData_throwsQrCodeGenerationException() {
        assertThatThrownBy(() -> qrCodeService.generateQrCodePng(null, 250, 250))
                .isInstanceOf(QrCodeGenerationException.class)
                .hasMessageContaining("Failed to generate QR code")
                .hasCauseInstanceOf(NullPointerException.class);
    }

    @Test
    void generateQrCodePng_withVerySmallDimensions_throwsQrCodeGenerationException() {
        // QR codes have minimum size requirements; extremely small dimensions should fail
        assertThatThrownBy(() -> qrCodeService.generateQrCodePng("https://example.com", 1, 1))
                .isInstanceOf(QrCodeGenerationException.class)
                .hasMessageContaining("Failed to generate QR code");
    }
}

package com.schwab.urlShortener.api;

import com.schwab.urlShortener.domain.ShortLink;
import com.schwab.urlShortener.service.QrCodeGenerationException;
import com.schwab.urlShortener.service.QrCodeService;
import com.schwab.urlShortener.service.ShortLinkNotFoundException;
import com.schwab.urlShortener.service.ShortLinkService;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.WebMvcTest;
import org.springframework.boot.test.mock.mockito.MockBean;
import org.springframework.http.MediaType;
import org.springframework.test.context.TestPropertySource;
import org.springframework.test.web.servlet.MockMvc;

import java.time.Instant;

import static org.mockito.ArgumentMatchers.anyString;
import static org.mockito.ArgumentMatchers.eq;
import static org.mockito.Mockito.*;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.get;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;

@WebMvcTest(ShortLinkController.class)
@TestPropertySource(properties = {
        "app.base-url=https://short.link/",
        "app.redirect-path=r/"
})
class ShortLinkControllerQrTest {

    @Autowired
    private MockMvc mockMvc;

    @MockBean
    private ShortLinkService service;

    @MockBean
    private QrCodeService qrCodeService;

    @Test
    void getQrCode_withValidShortCode_returns200WithPngContentType() throws Exception {
        ShortLink shortLink = new ShortLink("abc123", "https://example.com", Instant.now());
        when(service.resolve("abc123")).thenReturn(shortLink);

        byte[] mockQrCode = new byte[]{(byte) 0x89, 0x50, 0x4E, 0x47, 0x0D, 0x0A, 0x1A, 0x0A};
        when(qrCodeService.generateQrCodePng(anyString(), eq(250), eq(250))).thenReturn(mockQrCode);

        mockMvc.perform(get("/api/v1/links/abc123/qr"))
                .andExpect(status().isOk())
                .andExpect(content().contentType(MediaType.IMAGE_PNG))
                .andExpect(content().bytes(mockQrCode))
                .andExpect(header().string("Content-Type", "image/png"));
    }

    @Test
    void getQrCode_withValidShortCode_passesCorrectUrlToQrCodeService() throws Exception {
        ShortLink shortLink = new ShortLink("abc123", "https://example.com/long", Instant.now());
        when(service.resolve("abc123")).thenReturn(shortLink);

        byte[] mockQrCode = new byte[]{1, 2, 3};
        when(qrCodeService.generateQrCodePng(anyString(), eq(250), eq(250))).thenReturn(mockQrCode);

        mockMvc.perform(get("/api/v1/links/abc123/qr"))
                .andExpect(status().isOk());

        verify(qrCodeService).generateQrCodePng("https://short.link/r/abc123", 250, 250);
    }

    @Test
    void getQrCode_withUnknownShortCode_returns404() throws Exception {
        when(service.resolve("unknown")).thenThrow(new ShortLinkNotFoundException("unknown"));

        mockMvc.perform(get("/api/v1/links/unknown/qr"))
                .andExpect(status().isNotFound());

        verify(qrCodeService, never()).generateQrCodePng(anyString(), anyInt(), anyInt());
    }

    @Test
    void getQrCode_whenQrCodeServiceThrowsException_returns500() throws Exception {
        ShortLink shortLink = new ShortLink("abc123", "https://example.com", Instant.now());
        when(service.resolve("abc123")).thenReturn(shortLink);

        when(qrCodeService.generateQrCodePng(anyString(), eq(250), eq(250)))
                .thenThrow(new QrCodeGenerationException("Failed to generate QR code", new RuntimeException("ZXing error")));

        mockMvc.perform(get("/api/v1/links/abc123/qr"))
                .andExpect(status().isInternalServerError())
                .andExpect(jsonPath("$.title").value("QR Code Generation Failed"))
                .andExpect(jsonPath("$.status").value(500));
    }

    @Test
    void getQrCode_whenShortCodeResolutionThrowsUnexpectedException_propagatesException() throws Exception {
        when(service.resolve("error")).thenThrow(new RuntimeException("Database error"));

        mockMvc.perform(get("/api/v1/links/error/qr"))
                .andExpect(status().is5xxServerError());
    }

    @Test
    void getQrCode_withDifferentShortCode_constructsCorrectUrl() throws Exception {
        ShortLink shortLink = new ShortLink("xyz789", "https://another.com", Instant.now());
        when(service.resolve("xyz789")).thenReturn(shortLink);

        byte[] mockQrCode = new byte[]{1, 2, 3};
        when(qrCodeService.generateQrCodePng(anyString(), eq(250), eq(250))).thenReturn(mockQrCode);

        mockMvc.perform(get("/api/v1/links/xyz789/qr"))
                .andExpect(status().isOk());

        verify(qrCodeService).generateQrCodePng("https://short.link/r/xyz789", 250, 250);
    }

    @Test
    void getQrCode_invokesServiceResolveExactlyOnce() throws Exception {
        ShortLink shortLink = new ShortLink("abc123", "https://example.com", Instant.now());
        when(service.resolve("abc123")).thenReturn(shortLink);

        byte[] mockQrCode = new byte[]{1, 2, 3};
        when(qrCodeService.generateQrCodePng(anyString(), eq(250), eq(250))).thenReturn(mockQrCode);

        mockMvc.perform(get("/api/v1/links/abc123/qr"));

        verify(service, times(1)).resolve("abc123");
    }

    @Test
    void getQrCode_withValidRequest_returnsNonEmptyBody() throws Exception {
        ShortLink shortLink = new ShortLink("abc123", "https://example.com", Instant.now());
        when(service.resolve("abc123")).thenReturn(shortLink);

        byte[] mockQrCode = new byte[100];
        when(qrCodeService.generateQrCodePng(anyString(), eq(250), eq(250))).thenReturn(mockQrCode);

        mockMvc.perform(get("/api/v1/links/abc123/qr"))
                .andExpect(status().isOk())
                .andExpect(content().bytes(mockQrCode));
    }
}
